const body = $input.first().json.body || $input.first().json;
const memberName = body.member_name;
const facility = body.facility;
const bargainingUnit = body.bargaining_unit;
const hireDate = body.hire_date;

if (!memberName || !facility) {
  throw new Error('Missing required fields: member_name and facility');
}

return [{
  json: {
    member_name: memberName,
    facility: facility,
    bargaining_unit: bargainingUnit || 'TBD',
    hire_date: hireDate || new Date().toISOString().split('T')[0]
  }
}];

const member = $input.first().json;
const now = new Date().toISOString().split('T')[0];

// Calculate 30-day check-in date
const thirtyDays = new Date();
thirtyDays.setDate(thirtyDays.getDate() + 30);
const checkInDate = thirtyDays.toISOString().split('T')[0];

// Predefined orientation checklist
const checklist = [
  {
    title: `Welcome packet: ${member.member_name}`,
    description: `Prepare and deliver welcome packet for new member ${member.member_name} at ${member.facility}. Include: union constitution, contract summary, steward contact info, grievance procedure overview.`,
    due_offset_days: 1,
    priority: 'high'
  },
  {
    title: `Union rights orientation: ${member.member_name}`,
    description: `Schedule and conduct Weingarten rights orientation for ${member.member_name}. Cover: right to representation, grievance process, contract highlights for ${member.bargaining_unit}.`,
    due_offset_days: 3,
    priority: 'high'
  },
  {
    title: `Benefits enrollment review: ${member.member_name}`,
    description: `Review union benefits enrollment with ${member.member_name}. Ensure they understand health insurance options, pension enrollment, and any supplemental benefits under ${member.bargaining_unit} contract.`,
    due_offset_days: 5,
    priority: 'medium'
  },
  {
    title: `Introduce to steward: ${member.member_name}`,
    description: `Connect ${member.member_name} with their floor/unit steward at ${member.facility}. Ensure they know who to contact for workplace issues.`,
    due_offset_days: 3,
    priority: 'high'
  },
  {
    title: `Dues authorization: ${member.member_name}`,
    description: `Collect signed dues authorization card from ${member.member_name}. Verify payroll deduction is set up with HR at ${member.facility}.`,
    due_offset_days: 7,
    priority: 'high'
  },
  {
    title: `Add to communication channels: ${member.member_name}`,
    description: `Add ${member.member_name} to facility-specific email list, Teams channel, and any ${member.bargaining_unit} group communications.`,
    due_offset_days: 2,
    priority: 'medium'
  },
  {
    title: `Contract copy delivery: ${member.member_name}`,
    description: `Provide ${member.member_name} with a copy of the current collective bargaining agreement for ${member.bargaining_unit} at ${member.facility}.`,
    due_offset_days: 1,
    priority: 'medium'
  }
];

// Build task items with calculated due dates
const tasks = checklist.map(item => {
  const dueDate = new Date();
  dueDate.setDate(dueDate.getDate() + item.due_offset_days);
  return {
    json: {
      title: item.title,
      description: item.description,
      due_date: dueDate.toISOString().split('T')[0],
      priority: item.priority,
      tag: 'orientation',
      assigned_to: 'execsec',
      member_name: member.member_name,
      facility: member.facility,
      bargaining_unit: member.bargaining_unit
    }
  };
});

// Add 30-day check-in task for Dave
tasks.push({
  json: {
    title: `30-day check-in: ${member.member_name}`,
    description: `Follow up with ${member.member_name} (${member.facility}, ${member.bargaining_unit}). Hired: ${member.hire_date}. Check: Are they settling in? Any workplace concerns? Connected with steward? Benefits questions?`,
    due_date: checkInDate,
    priority: 'medium',
    tag: 'orientation',
    assigned_to: 'dave',
    member_name: member.member_name,
    facility: member.facility,
    bargaining_unit: member.bargaining_unit,
    is_30day_checkin: true
  }
});

return tasks;

const allItems = $input.all();
const taskCount = allItems.length;
const memberName = allItems[0]?.json?.title?.match(/: (.+)$/)?.[1] || 'new member';

return [{
  json: {
    success: true,
    tasks_created: taskCount,
    member_name: memberName,
    message: `Created ${taskCount} orientation tasks for ${memberName}`
  }
}];
